{"operationName":"Layout","variables":{"skipOrderIncompleteCount":false,"skipInventoryAllocationRequestIncompleteCount":false,"skipInventoryOutboundOrderIncompleteCount":false,"skipInventoryInboundOrderIncompleteCount":false},"extensions":{"clientLibrary":{"name":"@apollo/client","version":"4.1.6"}},"query":"query Layout($skipOrderIncompleteCount: Boolean!, $skipInventoryAllocationRequestIncompleteCount: Boolean!, $skipInventoryOutboundOrderIncompleteCount: Boolean!, $skipInventoryInboundOrderIncompleteCount: Boolean!) {
