{"operationName":"ProductVariantsResourcePicker","variables":{"after":null,"first":250,"displaysInventory":false,"locationID":"","filter":{}},"extensions":{"clientLibrary":{"name":"@apollo/client","version":"4.1.6"}},"query":"query ProductVariantsResourcePicker($after: String, $first: Int, $locationID: ID!, $displaysInventory: Boolean!, $filter: ProductVariantFilter) {
