{"operationName":"InventoryInboundOrdersPage","variables":{"first":30,"after":null,"filter":{"workingStatuses":["WAITING"]},"locationID":"","hasLocationID":false},"extensions":{"clientLibrary":{"name":"@apollo/client","version":"4.1.6"}},"query":"query InventoryInboundOrdersPage($first: Int, $after: String, $filter: InventoryInboundOrderFilter, $locationID: ID!, $hasLocationID: Boolean!) {
  inventoryInboundOrders(
    first: $first
    after: $after
    filter: $filter
    isReverse: true
  ) {
    nodes {
      id
      managementCode
      kind
      workingStatus
      inventoryLocation {
        id
        name
        __typename
      }
      createdAt
      __typename
    }
    pageInfo {
      hasNextPage
      endCursor
      hasPreviousPage
      __typename
    }
    __typename
  }
  location(id: $locationID) @include(if: $hasLocationID) {
    id
    name
    __typename
  }
  onHoldCount: inventoryInboundOrderCount(filter: {workingStatuses: [ON_HOLD]})
  waitingCount: inventoryInboundOrderCount(filter: {workingStatuses: [WAITING]})
  requestedCount: inventoryInboundOrderCount(
    filter: {workingStatuses: [REQUESTED]}
  )
  inProgressCount: inventoryInboundOrderCount(
    filter: {workingStatuses: [IN_PROGRESS]}
  )
  underInvestigationCount: inventoryInboundOrderCount(
    filter: {workingStatuses: [UNDER_INVESTIGATION]}
  )
}"}

